-- OTR Catalog CMD Finance
-- Generated from MASTER OTR DATUN.xlsx (696 baris, dedup dari 702)

CREATE TABLE IF NOT EXISTS dsd_otr_catalog (
  id          BIGSERIAL PRIMARY KEY,
  brand       TEXT NOT NULL,
  tipe        TEXT NOT NULL,
  ltv         NUMERIC(4,2),
  ltv_rule    TEXT,
  kategori    TEXT,
  otr_2026    BIGINT, otr_2025 BIGINT, otr_2024 BIGINT, otr_2023 BIGINT,
  otr_2022    BIGINT, otr_2021 BIGINT, otr_2020 BIGINT, otr_2019 BIGINT,
  otr_2018    BIGINT, otr_2017 BIGINT, otr_2016 BIGINT, otr_2015 BIGINT,
  leasing_key TEXT NOT NULL DEFAULT 'CMD',
  created_at  TIMESTAMPTZ DEFAULT NOW(),
  updated_at  TIMESTAMPTZ DEFAULT NOW()
);

CREATE UNIQUE INDEX IF NOT EXISTS dsd_otr_catalog_uniq
  ON dsd_otr_catalog(leasing_key, brand, tipe);

ALTER TABLE dsd_otr_catalog ENABLE ROW LEVEL SECURITY;
DO $$ BEGIN
  IF NOT EXISTS (SELECT 1 FROM pg_policies WHERE tablename='dsd_otr_catalog' AND policyname='read_all') THEN
    CREATE POLICY "read_all"  ON dsd_otr_catalog FOR SELECT USING (true);
  END IF;
  IF NOT EXISTS (SELECT 1 FROM pg_policies WHERE tablename='dsd_otr_catalog' AND policyname='write_auth') THEN
    CREATE POLICY "write_auth" ON dsd_otr_catalog FOR ALL USING (auth.role() = 'authenticated');
  END IF;
END $$;

ON CONFLICT (leasing_key, brand, tipe) DO UPDATE SET
  ltv=EXCLUDED.ltv, ltv_rule=EXCLUDED.ltv_rule, kategori=EXCLUDED.kategori,
  otr_2026=EXCLUDED.otr_2026, otr_2025=EXCLUDED.otr_2025, otr_2024=EXCLUDED.otr_2024,
  otr_2023=EXCLUDED.otr_2023, otr_2022=EXCLUDED.otr_2022, otr_2021=EXCLUDED.otr_2021,
  otr_2020=EXCLUDED.otr_2020, otr_2019=EXCLUDED.otr_2019, otr_2018=EXCLUDED.otr_2018,
  otr_2017=EXCLUDED.otr_2017, otr_2016=EXCLUDED.otr_2016, otr_2015=EXCLUDED.otr_2015,
  updated_at=NOW();
